// Récupère la date demandée par le frontend (format YYYY-MM-DD)
const body = $input.first().json.body || $input.first().json;
const dateStr = body.date; // ex: "2024-04-15"

// ── Calcul de l'offset DST Europe/Paris ──────────────────────────────────────
// Heure d'été (CEST = UTC+2) : dernier dimanche de mars → dernier dimanche d'octobre
// Heure d'hiver (CET  = UTC+1) : reste de l'année
const d = new Date(dateStr);
const year = d.getFullYear();

// Dernier dimanche de mars
const dstStart = new Date(year, 2, 31);
dstStart.setDate(31 - dstStart.getDay());

// Dernier dimanche d'octobre
const dstEnd = new Date(year, 9, 31);
dstEnd.setDate(31 - dstEnd.getDay());

const isDST = (d >= dstStart && d < dstEnd);
const offsetMinutes = isDST ? 120 : 60; // +2h ou +1h en minutes
const offsetStr = isDST ? '+02:00' : '+01:00';

// ── Génération des créneaux de la journée ────────────────────────────────────
// Horaires : Lun–Ven 9h–19h30, Sam 10h–12h, Dim fermé
// Durée : 30 min
const dow = d.getDay(); // 0=dim, 1=lun, ..., 6=sam

const slots = [];

if (dow === 0) {
  // Dimanche : fermé, on retourne un tableau vide
} else if (dow === 6) {
  // Samedi : 10h–12h
  for (let h = 10; h < 12; h++) {
    for (let m = 0; m < 60; m += 30) {
      slots.push(String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0'));
    }
  }
} else {
  // Lundi–Vendredi : 9h–19h30
  for (let h = 9; h < 20; h++) {
    const maxMin = (h === 19) ? 30 : 60;
    for (let m = 0; m < maxMin; m += 30) {
      slots.push(String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0'));
    }
  }
}

// ── Construction des plages ISO pour Google Calendar ─────────────────────────
// On construit timeMin = début de journée, timeMax = fin de journée en UTC
const dayStartLocal = new Date(dateStr + 'T00:00:00' + offsetStr);
const dayEndLocal   = new Date(dateStr + 'T23:59:59' + offsetStr);

return [{
  json: {
    date: dateStr,
    slots,
    offsetStr,
    offsetMinutes,
    timeMin: dayStartLocal.toISOString(),
    timeMax: dayEndLocal.toISOString()
  }
}];

// Récupère tous les items : événements GCal + données du nœud précédent
const allItems = $input.all();

// Le premier item contient les créneaux générés (passé via le nœud Code)
// Les items suivants sont les événements Google Calendar
// Note : avec le node GCal GetAll, chaque événement est un item séparé

// ── Récupère les données du nœud "Générer les créneaux du jour" ──────────────
const slotsData = $('Générer les créneaux du jour').first().json;
const { date, slots, offsetMinutes } = slotsData;

// ── Récupère les événements GCal ─────────────────────────────────────────────
// Chaque item est un événement avec json.start.dateTime etc.
const events = allItems
  .map(item => item.json)
  .filter(ev => ev.start && (ev.start.dateTime || ev.start.date));

// ── Pour chaque créneau, vérifie s'il est occupé ─────────────────────────────
const busySlots = new Set();

for (const ev of events) {
  const evStart = new Date(ev.start.dateTime || ev.start.date);
  const evEnd   = new Date(ev.end.dateTime   || ev.end.date);

  for (const slot of slots) {
    const [hh, mm] = slot.split(':').map(Number);
    // Convertit le créneau local en UTC
    const slotStartUTC = new Date(date + 'T00:00:00Z');
    slotStartUTC.setUTCMinutes(slotStartUTC.getUTCMinutes() + hh * 60 + mm - offsetMinutes);
    const slotEndUTC = new Date(slotStartUTC.getTime() + 30 * 60 * 1000);

    // Chevauchement : slot est occupé si evStart < slotEnd && evEnd > slotStart
    if (evStart < slotEndUTC && evEnd > slotStartUTC) {
      busySlots.add(slot);
    }
  }
}

const availableSlots = slots.filter(s => !busySlots.has(s));

return [{ json: { slots: availableSlots } }];
